class Solution {
    public int palindromePartition(String s, int k) {
        int n = s.length();
        int[][] dp = new int[n + 1][k + 1];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= k; j++) {
                dp[i][j] = Integer.MAX_VALUE;
            }
        }
        dp[0][0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= Math.min(i, k); j++) {
                for (int l = 1; l <= i; l++) {
                    int count = countChanges(s, i - l, i);
                    dp[i][j] = Math.min(dp[i][j], dp[i - l][j - 1] + count);
                }
            }
        }
        return dp[n][k];
    }

    private int countChanges(String s, int start, int end) {
        int count = 0;
        while (start < end) {
            if (s.charAt(start) != s.charAt(end)) {
                count++;
            }
            start++;
            end--;
        }
        return count;
    }
}
